#include <iostream>
#include <fstream>
#include <string>
#include <sstream>

using namespace std;

// Function to count the number of occurrences of a word in a string
int countWordOccurrences(string str, string word) {
    int count = 0;
    string temp = "";

    for(int i = 0; i <= str.length() - word.length(); i++) {
        temp = str.substr(i, word.length());
        if(temp == word) {
            count++;
            i += word.length()-1;
        }
    }

    return count;
}

int main() {
    string line, word;
    ifstream file;
    int count = 0;

    // Open the file
    file.open("sample.txt");

    // Check if the file is opened
    if(!file.is_open()) {
        cout << "Unable to open file";
        return 0;
    }

    cout << "Enter the word to search: ";
    cin >> word;

    // Read the file line by line
    while(getline(file, line)) {
        // Count the occurrences of the word in the line
        count += countWordOccurrences(line, word);
    }

    // Print the number of occurrences
    cout << "The word " << word << " appears " << count << " times in the file.";

    return 0;
}
```

This program first opens a file called "sample.txt". It then prompts the user to enter a word to search for in the file. For each line in the file, it counts the number of occurrences of the input word using a helper function `countWordOccurrences()`. Finally, it prints the total number of occurrences of the input word in the file.

